      "docsLabel": "nostr",
      "blurb": "Decentralized protocol; encrypted DMs via NIP-04.",
      "order": 55,
      "quickstartAllowFrom": true
    },
    "install": {
      "npmSpec": "@openclaw/nostr",
      "defaultChoice": "npm",
      "minHostVersion": ">=2026.4.1"
    },
    "release": {
      "publishToNpm": true
    }
  }
}
```

**Telegram Example (note `private: true` for bundled plugins):**
