#### File 13: `extensions/pulseboard/src/normalize.ts`

Exports: `normalizePulseboardMessagingTarget`, `looksLikePulseboardTargetId`, `isBoardTarget`, `normalizePulseboardAllowEntry`, `normalizePulseboardAllowlist`.

PulseBoard target rules:
- Group (board) targets: `@board-name` (leading `@`).
- DM targets: plain `username` (no `@`, no special chars).
- `isBoardTarget(target)`: `target.startsWith("@")`.
- `normalizePulseboardMessagingTarget`: strips `pulseboard:` prefix, `board:` prefix (adds `@` if missing), `user:` prefix. Validates with `looksLikePulseboardTargetId`.
- `looksLikePulseboardTargetId`: must match `/^@?[a-zA-Z0-9_-]+$/` (slug-like).
- `normalizePulseboardAllowEntry`: lowercases, strips `pulseboard:` and `user:` prefixes.

No imports from IRC-specific paths. No dependency on external libs.

```typescript
const PULSEBOARD_TARGET_PATTERN = /^@?[a-zA-Z0-9_][a-zA-Z0-9_-]*$/u;

export function isBoardTarget(target: string): boolean {
  return target.startsWith("@");
}

export function looksLikePulseboardTargetId(raw: string): boolean {
  return PULSEBOARD_TARGET_PATTERN.test(raw.trim());
}

export function normalizePulseboardMessagingTarget(raw: string): string | undefined {
  let target = raw.trim();
  if (!target) return undefined;
  const lowered = target.toLowerCase();
  if (lowered.startsWith("pulseboard:")) target = target.slice("pulseboard:".length).trim();
  if (target.toLowerCase().startsWith("board:")) {
    target = target.slice("board:".length).trim();
    if (!target.startsWith("@")) target = `@${target}`;
  }
  if (target.toLowerCase().startsWith("user:")) target = target.slice("user:".length).trim();
  if (!target || !looksLikePulseboardTargetId(target)) return undefined;
  return target;
}

export function normalizePulseboardAllowEntry(raw: string): string {
  let value = raw.trim().toLowerCase();
  if (value.startsWith("pulseboard:")) value = value.slice("pulseboard:".length);
  if (value.startsWith("user:")) value = value.slice("user:".length);
  return value.trim();
}

export function normalizePulseboardAllowlist(entries?: Array<string | number>): string[] {
  return (entries ?? []).map((e) => normalizePulseboardAllowEntry(String(e))).filter(Boolean);
}

export function formatPulseboardSenderId(message: PulseboardInboundMessage): string {
  return message.senderUsername.trim();
}
```

Note: `PulseboardInboundMessage` is imported from `./types.js`.

