```typescript
import { resolvePulseboardAccount } from "./accounts.js";
import { createPulseboardClient } from "./client.js";
import { normalizePulseboardMessagingTarget, isBoardTarget } from "./normalize.js";
import { getPulseboardRuntime } from "./runtime.js";
import type { CoreConfig } from "./types.js";

export type SendPulseboardOptions = {
  cfg?: CoreConfig;
  accountId?: string;
  replyTo?: string;
};

export type SendPulseboardResult = {
  messageId: string;
  target: string;
};

export async function sendMessagePulseboard(
  to: string,
  text: string,
  opts: SendPulseboardOptions = {},
): Promise<SendPulseboardResult> {
  const runtime = getPulseboardRuntime();
  const cfg = (opts.cfg ?? runtime.config.loadConfig()) as CoreConfig;
  const account = resolvePulseboardAccount({ cfg, accountId: opts.accountId });

  if (!account.configured) {
    throw new Error(`PulseBoard is not configured for account "${account.accountId}".`);
  }

  const target = normalizePulseboardMessagingTarget(to);
  if (!target) throw new Error(`Invalid PulseBoard target: ${to}`);

  const payload = opts.replyTo ? `${text.trim()}\n\n[reply:${opts.replyTo}]` : text.trim();
  if (!payload) throw new Error("Message must be non-empty for PulseBoard sends");

  const client = createPulseboardClient({
    apiUrl: account.apiUrl,
    apiKey: account.apiKey,
    username: account.username,
  });

  let result: { messageId: string };
  if (isBoardTarget(target)) {
    const boardName = target.slice(1); // strip leading "@"
    result = await client.sendToBoard(boardName, payload);
  } else {
    result = await client.sendDm(target, payload);
  }

  // record outbound activity
  try {
    runtime.channel.activity.record({ channel: "pulseboard", accountId: account.accountId, direction: "outbound" });
  } catch { /* runtime may not be initialized during setup */ }

  return { messageId: result.messageId, target };
}
```

