```typescript
import { resolvePulseboardAccount } from "./accounts.js";
import { createPulseboardClient } from "./client.js";
import type { CoreConfig, PulseboardProbe } from "./types.js";

export async function probePulseboard(
  cfg: CoreConfig,
  opts?: { accountId?: string; timeoutMs?: number },
): Promise<PulseboardProbe> {
  const account = resolvePulseboardAccount({ cfg, accountId: opts?.accountId });
  const base: PulseboardProbe = {
    ok: false,
    apiUrl: account.apiUrl,
    username: account.username,
  };
  if (!account.configured) return { ...base, error: "missing apiUrl, apiKey, or username" };

  const client = createPulseboardClient({
    apiUrl: account.apiUrl, apiKey: account.apiKey, username: account.username,
    connectTimeoutMs: opts?.timeoutMs ?? 8000,
  });
  try {
    const result = await client.ping();
    return { ...base, ok: result.ok, latencyMs: result.latencyMs };
  } catch (err) {
    return { ...base, error: err instanceof Error ? err.message : String(err) };
  }
}
