Group policy resolution helpers (mirrors IRC's `policy.ts`):

```typescript
import type { PulseBoardGroupConfig, PulseBoardAccountConfig } from "./types.js";

export type PulseBoardGroupMatch = {
  allowed: boolean;
  groupConfig?: PulseBoardGroupConfig;
  wildcardConfig?: PulseBoardGroupConfig;
  hasConfiguredBoards: boolean;
};

export function resolvePulseBoardGroupMatch(params: {
  boards?: Record<string, PulseBoardGroupConfig>;
  target: string; // normalized board target e.g. "@general"
}): PulseBoardGroupMatch {
  const boards = params.boards ?? {};
  const hasConfiguredBoards = Object.keys(boards).length > 0;

  const direct = boards[params.target];
  if (direct) {
    return { allowed: true, groupConfig: direct, wildcardConfig: boards["*"], hasConfiguredBoards };
  }
  // Case-insensitive match
  const targetLower = params.target.toLowerCase();
  const key = Object.keys(boards).find((k) => k.toLowerCase() === targetLower);
  if (key) {
    const matched = boards[key];
    if (matched) {
      return { allowed: true, groupConfig: matched, wildcardConfig: boards["*"], hasConfiguredBoards };
    }
  }
  // Wildcard match
  if (boards["*"]) {
    return { allowed: true, wildcardConfig: boards["*"], hasConfiguredBoards };
  }
  return { allowed: false, wildcardConfig: boards["*"], hasConfiguredBoards };
}

export function resolvePulseBoardRequireMention(params: {
  groupConfig?: PulseBoardGroupConfig;
  wildcardConfig?: PulseBoardGroupConfig;
}): boolean {
  if (typeof params.groupConfig?.requireMention === "boolean") {
    return params.groupConfig.requireMention;
  }
  if (typeof params.wildcardConfig?.requireMention === "boolean") {
    return params.wildcardConfig.requireMention;
  }
  return true; // default: require @mention in boards
}
