Inbound message handling — follows IRC pattern but uses public SDK paths:

```typescript
import type { ResolvedPulseBoardAccount } from "./accounts.js";
import { normalizePulseBoardAllowlist } from "./normalize.js";
import { resolvePulseBoardGroupMatch, resolvePulseBoardRequireMention } from "./policy.js";
import { getPulseBoardRuntime } from "./runtime.js";
import { logInboundDrop, resolveMentionGating } from "openclaw/plugin-sdk/channel-inbound";
import {
  dispatchInboundDirectDmWithRuntime,
  resolveInboundDirectDmAccessWithRuntime,
} from "openclaw/plugin-sdk/direct-dm";
import { readStoreAllowFromForDmPolicy, resolveEffectiveAllowFromLists } from "openclaw/plugin-sdk/channel-policy";
import type { RuntimeEnv } from "./runtime-api.js";
import { sendMessagePulseBoard } from "./send.js";
import type { CoreConfig, PulseBoardInboundMessage } from "./types.js";

const CHANNEL_ID = "pulseboard" as const;

export async function handlePulseBoardInbound(params: {
  message: PulseBoardInboundMessage;
  account: ResolvedPulseBoardAccount;
  config: CoreConfig;
  runtime: RuntimeEnv;
  sendReply: (target: string, text: string, replyToId?: string) => Promise<void>;
  statusSink?: (patch: { lastInboundAt?: number; lastOutboundAt?: number }) => void;
}): Promise<void> {
  const { message, account, config, runtime } = params;
  const core = getPulseBoardRuntime();

  const dmPolicy = account.config.dmPolicy ?? "pairing";
  const configAllowFrom = normalizePulseBoardAllowlist(account.config.allowFrom);

  const storeAllowFrom = readStoreAllowFromForDmPolicy({
    channel: CHANNEL_ID,
    accountId: account.accountId,
    dmPolicy,
    runtime: core,
  });

  const { effectiveAllowFrom } = resolveEffectiveAllowFromLists({
    allowFrom: configAllowFrom,
    groupAllowFrom: normalizePulseBoardAllowlist(account.config.groupAllowFrom),
    storeAllowFrom,
    dmPolicy,
    groupAllowFromFallbackToAllowFrom: false,
  });

  if (!message.isGroup) {
    // DM handling
    const access = await resolveInboundDirectDmAccessWithRuntime({
      cfg: config,
      channel: CHANNEL_ID,
      accountId: account.accountId,
      senderId: message.senderUsername.toLowerCase(),
      allowFrom: effectiveAllowFrom,
      dmPolicy,
      runtime: core,
      notifyApproval: async (id) => {
        await sendMessagePulseBoard(id, "Your DM request has been approved.", {
          cfg: config,
          accountId: account.accountId,
        });
      },
    });
    if (!access.allowed) {
      logInboundDrop({ channel: CHANNEL_ID, reason: access.reason ?? "dm-blocked", accountId: account.accountId });
      return;
    }
    params.statusSink?.({ lastInboundAt: message.timestamp });
    await dispatchInboundDirectDmWithRuntime({
      cfg: config,
      channel: CHANNEL_ID,
      accountId: account.accountId,
      target: message.target,
      senderId: message.senderUsername,
      text: message.text,
      messageId: message.messageId,
      timestamp: message.timestamp,
      runtime: core,
      sendReply: params.sendReply,
    });
    return;
  }

  // Group/board handling
  const groupMatch = resolvePulseBoardGroupMatch({
    boards: account.config.boards,
    target: message.target,
  });
  const groupPolicy = account.config.groupPolicy ?? "allowlist";

  if (groupPolicy === "disabled") {
    logInboundDrop({ channel: CHANNEL_ID, reason: "group-policy-disabled", accountId: account.accountId });
    return;
  }
  if (groupPolicy === "allowlist" && !groupMatch.allowed) {
    logInboundDrop({ channel: CHANNEL_ID, reason: "group-not-allowlisted", accountId: account.accountId });
    return;
  }

  const requireMention = resolvePulseBoardRequireMention({
    groupConfig: groupMatch.groupConfig,
    wildcardConfig: groupMatch.wildcardConfig,
  });
  const mentionResult = resolveMentionGating({
    text: message.text,
    requireMention,
    botName: account.username,
  });
  if (!mentionResult.allowed) {
    // silently drop unmentioned group messages
    return;
  }

  params.statusSink?.({ lastInboundAt: message.timestamp });
  await dispatchInboundDirectDmWithRuntime({
    cfg: config,
    channel: CHANNEL_ID,
    accountId: account.accountId,
    target: message.target,
    senderId: message.senderUsername,
    text: mentionResult.strippedText ?? message.text,
    messageId: message.messageId,
    timestamp: message.timestamp,
    runtime: core,
    sendReply: params.sendReply,
  });
}
```

**Note**: `resolveMentionGating` takes `{ text, requireMention, botName }` — verify exact signature against `openclaw/plugin-sdk/channel-inbound`. If the exact signature differs, adjust accordingly. Similarly, `dispatchInboundDirectDmWithRuntime` signature should be verified against `openclaw/plugin-sdk/direct-dm`.

