```typescript
import { resolvePulseBoardAccount } from "./accounts.js";
import { normalizePulseBoardMessagingTarget } from "./normalize.js";
import { getPulseBoardRuntime } from "./runtime.js";
import type { CoreConfig } from "./types.js";

export type SendPulseBoardResult = {
  messageId: string;
  target: string;
};

function makePulseBoardMessageId(): string {
  return `pb-${Date.now().toString(36)}-${Math.random().toString(36).slice(2, 7)}`;
}

function recordPulseBoardOutboundActivity(accountId: string): void {
  try {
    getPulseBoardRuntime().channel.activity.record({
      channel: "pulseboard",
      accountId,
      direction: "outbound",
    });
  } catch (error) {
    if (!(error instanceof Error) || error.message !== "PulseBoard runtime not initialized") {
      throw error;
    }
  }
}

export async function sendMessagePulseBoard(
  to: string,
  text: string,
  opts: { cfg?: CoreConfig; accountId?: string; replyToId?: string } = {},
): Promise<SendPulseBoardResult> {
  const runtime = getPulseBoardRuntime();
  const cfg = (opts.cfg ?? runtime.config.loadConfig()) as CoreConfig;
  const account = resolvePulseBoardAccount({ cfg, accountId: opts.accountId });

  if (!account.configured) {
    throw new Error(
      `PulseBoard is not configured for account "${account.accountId}" (need apiUrl and username in channels.pulseboard).`,
    );
  }

  const target = normalizePulseBoardMessagingTarget(to);
  if (!target) throw new Error(`Invalid PulseBoard target: ${to}`);

  const payload = opts.replyToId ? `${text.trim()}\n\n[reply:${opts.replyToId}]` : text.trim();
  if (!payload) throw new Error("Message must be non-empty for PulseBoard sends");

  // Stub: in a real implementation, POST to account.apiUrl + "/messages" with auth header
  // For now, simulate success after a brief async yield
  await Promise.resolve();

  recordPulseBoardOutboundActivity(account.accountId);

  return { messageId: makePulseBoardMessageId(), target };
}

/**
 * Simple text chunker for PulseBoard's 4000-char limit.
 * Splits on newlines where possible, falls back to hard splits.
 */
export function chunkPulseBoardText(text: string, limit: number): string[] {
  if (text.length <= limit) return [text];
  const chunks: string[] = [];
  let remaining = text;
  while (remaining.length > limit) {
    // Try to split at a newline within limit
    const slice = remaining.slice(0, limit);
    const lastNewline = slice.lastIndexOf("\n");
    const splitAt = lastNewline > limit * 0.5 ? lastNewline + 1 : limit;
    chunks.push(remaining.slice(0, splitAt).trimEnd());
    remaining = remaining.slice(splitAt).trimStart();
  }
  if (remaining.trim()) chunks.push(remaining.trim());
  return chunks;
}
```

