  runtime?: RuntimeEnv;
  abortSignal?: AbortSignal;
  statusSink?: (patch: { lastInboundAt?: number; lastOutboundAt?: number }) => void;
};

export async function monitorPulseBoardProvider(opts: PulseBoardMonitorOptions): Promise<{ stop: () => void }> {
  const core = getPulseBoardRuntime();
  const cfg = opts.config ?? (core.config.loadConfig() as CoreConfig);
  const account = resolvePulseBoardAccount({ cfg, accountId: opts.accountId });

  const runtime: RuntimeEnv = resolveLoggerBackedRuntime(opts.runtime, core.logging.getChildLogger());

  if (!account.configured) {
    throw new Error(
      `PulseBoard is not configured for account "${account.accountId}" (need apiUrl and username in channels.pulseboard).`,
    );
  }

  const logger = core.logging.getChildLogger({ channel: "pulseboard", accountId: account.accountId });
  logger.info(`[${account.accountId}] PulseBoard provider started (${account.apiUrl} as ${account.username})`);

  let stopped = false;

  // Stub: in a real implementation, open a WebSocket or long-poll connection here.
  // PulseBoard is fictional, so we simply wait for the abort signal.
  const waitForStop = new Promise<void>((resolve) => {
    opts.abortSignal?.addEventListener("abort", () => {
      stopped = true;
      resolve();
    });
    if (opts.abortSignal?.aborted) {
      stopped = true;
      resolve();
    }
  });

  await waitForStop;

  return {
    stop: () => {
      stopped = true;
    },
  };
}
