import { resolvePulseBoardAccount } from "./accounts.js";
import type { CoreConfig, PulseBoardProbe } from "./types.js";

export async function probePulseBoard(
  cfg: CoreConfig,
  opts?: { accountId?: string; timeoutMs?: number },
): Promise<PulseBoardProbe> {
  const account = resolvePulseBoardAccount({ cfg, accountId: opts?.accountId });
  const base: PulseBoardProbe = {
    ok: false,
    apiUrl: account.apiUrl,
    username: account.username,
  };

  if (!account.configured) {
    return { ...base, error: "missing apiUrl or username" };
  }

  const started = Date.now();
  try {
    // Stub: in a real implementation, GET account.apiUrl + "/health" with auth header.
    // Simulate a fast success since PulseBoard is fictional.
    await new Promise<void>((resolve) => setTimeout(resolve, 10));
    const elapsed = Date.now() - started;
    return { ...base, ok: true, latencyMs: elapsed };
  } catch (err) {
    const error = err instanceof Error ? err.message : String(err);
    return { ...base, error };
  }
}
