### Step 13 — `extensions/pulseboard/src/normalize.ts`

Target normalization and allowlist helpers:

```typescript
const PULSEBOARD_BOARD_PREFIX = "@";
const PULSEBOARD_TARGET_PATTERN = /^[a-z0-9_-]+$/iu;

/** Returns true if the target refers to a board (group). */
export function isBoardTarget(target: string): boolean {
  return target.startsWith(PULSEBOARD_BOARD_PREFIX);
}

/** Normalize a raw PulseBoard target string. Returns undefined if invalid. */
export function normalizePulseBoardMessagingTarget(raw: string): string | undefined {
  const trimmed = raw.trim();
  if (!trimmed) return undefined;

  let target = trimmed;
  // Strip "pulseboard:" scheme prefix
  if (target.toLowerCase().startsWith("pulseboard:")) {
    target = target.slice("pulseboard:".length).trim();
  }
  // Strip "board:" prefix → add @ if missing
  if (target.toLowerCase().startsWith("board:")) {
    target = target.slice("board:".length).trim();
    if (!target.startsWith(PULSEBOARD_BOARD_PREFIX)) {
      target = `${PULSEBOARD_BOARD_PREFIX}${target}`;
    }
  }
  // Strip "user:" prefix
  if (target.toLowerCase().startsWith("user:")) {
    target = target.slice("user:".length).trim();
  }
  if (!target || !looksLikePulseBoardTargetId(target)) return undefined;
  return target.toLowerCase();
}

/** Returns true if the raw string looks like a valid PulseBoard target. */
export function looksLikePulseBoardTargetId(raw: string): boolean {
  const trimmed = raw.trim();
  if (!trimmed) return false;
  const check = trimmed.startsWith(PULSEBOARD_BOARD_PREFIX) ? trimmed.slice(1) : trimmed;
  return check.length > 0 && PULSEBOARD_TARGET_PATTERN.test(check);
}

/** Normalize an allowlist entry (for DM allowlists). Returns empty string if invalid. */
export function normalizePulseBoardAllowEntry(raw: string): string {
  let value = raw.trim().toLowerCase();
  if (!value) return "";
  if (value.startsWith("pulseboard:")) value = value.slice("pulseboard:".length);
  if (value.startsWith("user:")) value = value.slice("user:".length);
  // Boards should not appear in DM allowlists; strip @ prefix
  if (value.startsWith(PULSEBOARD_BOARD_PREFIX)) value = value.slice(1);
  return value.trim();
}

export function normalizePulseBoardAllowlist(entries?: Array<string | number>): string[] {
  return (entries ?? []).map((e) => normalizePulseBoardAllowEntry(String(e))).filter(Boolean);
}
```

