24	}) {
25	  return (
26	    challenge: Omit<
27	      Parameters<typeof issuePairingChallenge>[0],
28	      "channel" | "upsertPairingRequest"
29	    >,
30	  ) =>
31	    issuePairingChallenge({
32	      channel: params.channel,
33	      upsertPairingRequest: params.upsertPairingRequest,
34	      ...challenge,
35	    });
36	}
