63	/** Prefer multi-attachment payloads, then fall back to the legacy single-media field. */
64	export function resolveOutboundMediaUrls(payload: {
65	  mediaUrls?: string[];
66	  mediaUrl?: string;
67	}): string[] {
68	  if (payload.mediaUrls?.length) {
69	    return payload.mediaUrls;
70	  }
71	  if (payload.mediaUrl) {
72	    return [payload.mediaUrl];
73	  }
74	  return [];
