92	/** Check whether an outbound payload includes text, optionally trimming whitespace first. */
93	export function hasOutboundText(payload: { text?: string }, options?: { trim?: boolean }): boolean {
94	  const text = options?.trim ? payload.text?.trim() : payload.text;
95	  return Boolean(text);
