import {
  resolveLoggerBackedRuntime,
  runStoppablePassiveMonitor,
} from "openclaw/plugin-sdk/extension-shared";
import { resolvePulseBoardAccount } from "./accounts.js";
import { handlePulseBoardInbound } from "./inbound.js";
import { makePulseBoardMessageId } from "./send.js";
import type { RuntimeEnv } from "./runtime-api.js";
import { getPulseBoardRuntime } from "./runtime.js";
import type { CoreConfig, PulseBoardInboundMessage } from "./types.js";

export type PulseBoardMonitorOptions = {
  accountId?: string;
  config?: CoreConfig;
  runtime?: RuntimeEnv;
  abortSignal?: AbortSignal;
  statusSink?: (patch: { lastInboundAt?: number; lastOutboundAt?: number }) => void;
  onMessage?: (message: PulseBoardInboundMessage) => void | Promise<void>;
};

/**
 * Monitor the PulseBoard API for inbound messages.
 *
 * Stub implementation — a real PulseBoard client would open a WebSocket or
 * long-poll connection to receive board posts and DMs. Here we resolve the
 * account, log the connection, and wait until the abort signal fires.
 */
export async function monitorPulseBoardProvider(
  opts: PulseBoardMonitorOptions,
): Promise<{ stop: () => void }> {
  const core = getPulseBoardRuntime();
  const cfg = opts.config ?? (core.config.loadConfig() as CoreConfig);
  const account = resolvePulseBoardAccount({ cfg, accountId: opts.accountId });

  const runtime: RuntimeEnv = resolveLoggerBackedRuntime(
    opts.runtime,
    core.logging.getChildLogger(),
  );

  if (!account.configured) {
    throw new Error(
      `PulseBoard is not configured for account "${account.accountId}" ` +
        `(need apiUrl, apiKey, and username in channels.pulseboard).`,
    );
  }

  const logger = core.logging.getChildLogger({
    channel: "pulseboard",
    accountId: account.accountId,
  });

  let stopped = false;

  // Stub: a real implementation would call:
  //   GET  ${account.apiUrl}/api/v1/subscribe?username=${account.username}
  //   Authorization: Bearer ${account.apiKey}
  // and stream incoming message events via WebSocket or long-poll.

  logger.info(
    `[${account.accountId}] connected to PulseBoard (${account.apiUrl}) as ${account.username}`,
  );

  return {
    stop: () => {
      if (!stopped) {
        stopped = true;
        logger.info(`[${account.accountId}] PulseBoard monitor stopped`);
      }
    },
  };
}

export { makePulseBoardMessageId };
export { runStoppablePassiveMonitor };

