import { createAccountListHelpers } from "openclaw/plugin-sdk/account-helpers";
import { DEFAULT_ACCOUNT_ID, normalizeAccountId } from "openclaw/plugin-sdk/account-id";
import { resolveMergedAccountConfig } from "openclaw/plugin-sdk/account-resolution";
import { normalizeResolvedSecretInputString } from "openclaw/plugin-sdk/secret-input";
import type { CoreConfig, PulseBoardAccountConfig } from "./types.js";

const {
  listAccountIds: listPulseBoardAccountIds,
  resolveDefaultAccountId: resolveDefaultPulseBoardAccountId,
} = createAccountListHelpers("pulseboard", { normalizeAccountId });
export { listPulseBoardAccountIds, resolveDefaultPulseBoardAccountId };

export type ResolvedPulseBoardAccount = {
  accountId: string;
  enabled: boolean;
  name?: string;
  configured: boolean;
  apiUrl: string;
  apiKey: string;
  apiKeySource: "env" | "config" | "none";
  username: string;
  config: PulseBoardAccountConfig;
};

function mergePulseBoardAccountConfig(
  cfg: CoreConfig,
  accountId: string,
): PulseBoardAccountConfig {
  return resolveMergedAccountConfig<PulseBoardAccountConfig>({
    channelConfig: cfg.channels?.pulseboard as PulseBoardAccountConfig | undefined,
    accounts: cfg.channels?.pulseboard?.accounts as
      | Record<string, Partial<PulseBoardAccountConfig>>
      | undefined,
    accountId,
    omitKeys: ["defaultAccount"],
    normalizeAccountId,
  });
}

function resolveApiKey(
  accountId: string,
  merged: PulseBoardAccountConfig,
): { apiKey: string; source: "env" | "config" | "none" } {
  if (accountId === DEFAULT_ACCOUNT_ID) {
    const envKey = process.env.PULSEBOARD_API_KEY?.trim();
    if (envKey) {
      return { apiKey: envKey, source: "env" };
    }
  }
  const configKey = normalizeResolvedSecretInputString({
    value: merged.apiKey,
    path: `channels.pulseboard.accounts.${accountId}.apiKey`,
  });
  if (configKey) {
    return { apiKey: configKey, source: "config" };
  }
  return { apiKey: "", source: "none" };
}

export function resolvePulseBoardAccount(params: {
  cfg: CoreConfig;
  accountId?: string | null;
}): ResolvedPulseBoardAccount {
  const hasExplicitAccountId = Boolean(params.accountId?.trim());
  const baseEnabled = params.cfg.channels?.pulseboard?.enabled !== false;

  const resolve = (accountId: string): ResolvedPulseBoardAccount => {
    const merged = mergePulseBoardAccountConfig(params.cfg, accountId);
    const accountEnabled = merged.enabled !== false;
    const enabled = baseEnabled && accountEnabled;

    const apiUrl = (
      merged.apiUrl?.trim() ||
      (accountId === DEFAULT_ACCOUNT_ID ? process.env.PULSEBOARD_API_URL?.trim() : "") ||
      ""
    ).trim();

    const username = (
      merged.username?.trim() ||
      (accountId === DEFAULT_ACCOUNT_ID ? process.env.PULSEBOARD_USERNAME?.trim() : "") ||
      ""
    ).trim();

    const { apiKey, source: apiKeySource } = resolveApiKey(accountId, merged);

    const config: PulseBoardAccountConfig = {
      ...merged,
      apiUrl,
      apiKey,
      username,
    };

    return {
      accountId,
      enabled,
      name: merged.name?.trim() || undefined,
      configured: Boolean(apiUrl && apiKey && username),
      apiUrl,
      apiKey,
      apiKeySource,
      username,
      config,
    };
  };

  const normalized = normalizeAccountId(params.accountId);
  const primary = resolve(normalized);
  if (hasExplicitAccountId) {
    return primary;
  }
  if (primary.configured) {
    return primary;
  }

  const fallbackId = resolveDefaultPulseBoardAccountId(params.cfg);
  if (fallbackId === primary.accountId) {
    return primary;
  }
  const fallback = resolve(fallbackId);
  if (!fallback.configured) {
    return primary;
  }
  return fallback;
}

export function listEnabledPulseBoardAccounts(cfg: CoreConfig): ResolvedPulseBoardAccount[] {
  return listPulseBoardAccountIds(cfg)
    .map((accountId) => resolvePulseBoardAccount({ cfg, accountId }))
    .filter((account) => account.enabled);
}

import {
  buildChannelConfigSchema,
  DmPolicySchema,
  GroupPolicySchema,
  ReplyRuntimeConfigSchemaShape,
  ToolPolicySchema,
  requireOpenAllowFrom,
} from "openclaw/plugin-sdk/channel-config-schema";
import { z } from "openclaw/plugin-sdk/zod";
import { pulseBoardChannelConfigUiHints } from "./config-ui-hints.js";

const PulseBoardBoardSchema = z
  .object({
    requireMention: z.boolean().optional(),
    tools: ToolPolicySchema,
    toolsBySender: z.record(z.string(), ToolPolicySchema).optional(),
    skills: z.array(z.string()).optional(),
    enabled: z.boolean().optional(),
    allowFrom: z.array(z.union([z.string(), z.number()])).optional(),
    systemPrompt: z.string().optional(),
  })
  .strict();

export const PulseBoardAccountSchemaBase = z
  .object({
    name: z.string().optional(),
    enabled: z.boolean().optional(),
    apiUrl: z.string().optional(),
    apiKey: z.string().optional(),
    username: z.string().optional(),
    dmPolicy: DmPolicySchema.optional().default("pairing"),
    allowFrom: z.array(z.union([z.string(), z.number()])).optional(),
    groupPolicy: GroupPolicySchema.optional().default("allowlist"),
    groupAllowFrom: z.array(z.union([z.string(), z.number()])).optional(),
    boards: z.record(z.string(), PulseBoardBoardSchema.optional()).optional(),
    textChunkLimit: z.number().int().min(1).max(32000).optional(),
    blockStreaming: z.boolean().optional(),
    responsePrefix: z.string().optional(),
    ...ReplyRuntimeConfigSchemaShape,
  })
  .strict();

export const PulseBoardAccountSchema = PulseBoardAccountSchemaBase.superRefine((value, ctx) => {
  requireOpenAllowFrom({
    policy: value.dmPolicy,
    allowFrom: value.allowFrom,
    ctx,
    path: ["allowFrom"],
    message:
      'channels.pulseboard.dmPolicy="open" requires channels.pulseboard.allowFrom to include "*"',
  });
});

export const PulseBoardConfigSchema = PulseBoardAccountSchemaBase.extend({
  accounts: z.record(z.string(), PulseBoardAccountSchema.optional()).optional(),
  defaultAccount: z.string().optional(),
}).superRefine((value, ctx) => {
  requireOpenAllowFrom({
    policy: value.dmPolicy,
    allowFrom: value.allowFrom,
    ctx,
    path: ["allowFrom"],
    message:
      'channels.pulseboard.dmPolicy="open" requires channels.pulseboard.allowFrom to include "*"',
  });
});

export const PulseBoardChannelConfigSchema = buildChannelConfigSchema(PulseBoardConfigSchema, {
  uiHints: pulseBoardChannelConfigUiHints,
});

