function formatError(err: unknown): string {
  if (err instanceof Error) {
    return err.message;
  }
  return typeof err === "string" ? err : JSON.stringify(err);
}

/**
 * Probe the PulseBoard API connectivity for a given account.
 *
 * Stub implementation — a real client would issue:
 *   GET ${apiUrl}/api/v1/health
 *   Authorization: Bearer ${apiKey}
 * and measure the round-trip latency.
 */
export async function probePulseBoard(
  cfg: CoreConfig,
  opts?: { accountId?: string; timeoutMs?: number },
): Promise<PulseBoardProbe> {
  const account = resolvePulseBoardAccount({ cfg, accountId: opts?.accountId });
  const base: PulseBoardProbe = {
    ok: false,
    apiUrl: account.apiUrl,
    username: account.username,
  };

  if (!account.configured) {
    return {
      ...base,
      error: "missing apiUrl, apiKey, or username",
    };
  }

  const started = Date.now();
  try {
    // Stub: no real HTTP call for this fictional platform.
    // A real implementation would GET ${account.apiUrl}/api/v1/health
    // with Authorization: Bearer ${account.apiKey} and a timeout.
    const elapsed = Date.now() - started;
    return {
      ...base,
      ok: true,
      latencyMs: elapsed,
    };
  } catch (err) {
    return {
      ...base,
      error: formatError(err),
    };
  }
}

