      .join(", ");

    const raw = String(
      await prompter.text({
        message: "PulseBoard allowFrom (usernames, comma-separated)",
        placeholder: "alice, bob-smith",
        initialValue: existingStr || undefined,
        validate: () => undefined,
      }),
    ).trim();

    const allowFrom = parseListInput(raw)
      .map((entry) => normalizePulseBoardAllowEntry(entry))
      .filter(Boolean);

    return setPulseBoardAllowFrom(cfg as CoreConfig, allowFrom);
  },
};

export const pulseBoardSetupWizard: ChannelSetupWizard = {
  channel,
  status: createStandardChannelSetupStatus({
    channelLabel: "PulseBoard",
    configuredLabel: "configured",
    unconfiguredLabel: "needs apiUrl + apiKey + username",
    configuredHint: "configured",
    unconfiguredHint: "needs apiUrl + apiKey + username",
    configuredScore: 1,
    unconfiguredScore: 0,
    includeStatusLine: true,
    resolveConfigured: ({ cfg }) =>
      listPulseBoardAccountIds(cfg as CoreConfig).some(
        (accountId) => resolvePulseBoardAccount({ cfg: cfg as CoreConfig, accountId }).configured,
      ),
  }),
  introNote: {
    title: "PulseBoard setup",
    lines: [
      "PulseBoard needs an API URL, an API key, and a bot username.",
      'Board messages require @mention by default. Set channels.pulseboard.boards["@board"].requireMention=false to allow all messages.',
      'Use channels.pulseboard.groupPolicy="open" to allow messages from any board without an explicit allowlist.',
      "Env vars supported: PULSEBOARD_API_URL, PULSEBOARD_API_KEY, PULSEBOARD_USERNAME.",
      `Docs: ${formatDocsLink("/channels/pulseboard", "channels/pulseboard")}`,
    ],
    shouldShow: ({ cfg, accountId }) =>
      !resolvePulseBoardAccount({ cfg: cfg as CoreConfig, accountId }).configured,
  },
  prepare: async ({ cfg, accountId, credentialValues, prompter }) => {
    const resolved = resolvePulseBoardAccount({ cfg: cfg as CoreConfig, accountId });
    const isDefaultAccount = accountId === DEFAULT_ACCOUNT_ID;

    const envUrl = isDefaultAccount ? process.env.PULSEBOARD_API_URL?.trim() : "";
    const envKey = isDefaultAccount ? process.env.PULSEBOARD_API_KEY?.trim() : "";
    const envUser = isDefaultAccount ? process.env.PULSEBOARD_USERNAME?.trim() : "";
    const envReady =
      Boolean(envUrl && envKey && envUser) &&
      !resolved.config.apiUrl &&
      !resolved.config.apiKey &&
      !resolved.config.username;

    if (envReady) {
      const useEnv = await prompter.confirm({
        message:
          "PULSEBOARD_API_URL, PULSEBOARD_API_KEY, and PULSEBOARD_USERNAME detected. Use env vars?",
        initialValue: true,
      });
      if (useEnv) {
        return {
          cfg: updatePulseBoardAccountConfig(cfg as CoreConfig, accountId, { enabled: true }),
          credentialValues: { ...credentialValues, __pbUseEnv: "1" },
        };
      }
    }

    return {
      cfg: updatePulseBoardAccountConfig(cfg as CoreConfig, accountId, { enabled: true }),
      credentialValues: { ...credentialValues, __pbUseEnv: "0" },
    };
  },
  credentials: [],
  textInputs: [
    {
      inputKey: "apiUrl",
      message: "PulseBoard API URL",
      placeholder: "https://pulseboard.example.com",
      currentValue: ({ cfg, accountId }) =>
        resolvePulseBoardAccount({ cfg: cfg as CoreConfig, accountId }).config.apiUrl || undefined,
      shouldPrompt: ({ credentialValues }) => credentialValues["__pbUseEnv"] !== "1",
      validate: ({ value }) => (String(value ?? "").trim() ? undefined : "Required"),
      normalizeValue: ({ value }) => String(value).trim().replace(/\/+$/, ""),
      applySet: async ({ cfg, accountId, value }) =>
        updatePulseBoardAccountConfig(cfg as CoreConfig, accountId, {
          enabled: true,
          apiUrl: value,
        }),
    },
    {
      inputKey: "token",
      message: "PulseBoard API key",
      currentValue: ({ cfg, accountId }) =>
        resolvePulseBoardAccount({ cfg: cfg as CoreConfig, accountId }).config.apiKey || undefined,
      shouldPrompt: ({ credentialValues }) => credentialValues["__pbUseEnv"] !== "1",
      validate: ({ value }) => (String(value ?? "").trim() ? undefined : "Required"),
      normalizeValue: ({ value }) => String(value).trim(),
      applySet: async ({ cfg, accountId, value }) =>
        updatePulseBoardAccountConfig(cfg as CoreConfig, accountId, {
          enabled: true,
          apiKey: value,
        }),
    },
    {
      inputKey: "userId",
      message: "PulseBoard bot username",
      currentValue: ({ cfg, accountId }) =>
        resolvePulseBoardAccount({ cfg: cfg as CoreConfig, accountId }).config.username ||
        undefined,
      shouldPrompt: ({ credentialValues }) => credentialValues["__pbUseEnv"] !== "1",
      validate: ({ value }) => (String(value ?? "").trim() ? undefined : "Required"),
      normalizeValue: ({ value }) => String(value).trim(),
      applySet: async ({ cfg, accountId, value }) =>
        updatePulseBoardAccountConfig(cfg as CoreConfig, accountId, {
          enabled: true,
          username: value,
        }),
    },
    {
      inputKey: "groupChannels",
      message: "Board allowlist (optional, @board-name or *, comma-separated)",
      placeholder: "@general, @ops, *",
      required: false,
      applyEmptyValue: true,
      currentValue: ({ cfg, accountId }) => {
        const boards = resolvePulseBoardAccount({ cfg: cfg as CoreConfig, accountId }).config
          .boards;
        return boards ? Object.keys(boards).join(", ") : undefined;
      },
      shouldPrompt: ({ credentialValues }) => credentialValues["__pbUseEnv"] !== "1",
      normalizeValue: ({ value }) =>
        parseListInput(String(value))
          .map((entry) => normalizeBoardEntry(entry))
          .filter((entry): entry is string => entry !== null)
          .join(", "),
      applySet: async ({ cfg, accountId, value }) => {
        const entries = parseListInput(String(value))
          .map((entry) => normalizeBoardEntry(entry))
          .filter((entry): entry is string => entry !== null);
        if (entries.length === 0) {
          return cfg as CoreConfig;
        }
        return setPulseBoardGroupAccess(cfg as CoreConfig, accountId, "allowlist", entries);
      },
    },
  ],
  groupAccess: {
    label: "PulseBoard boards",
    placeholder: "@general, @ops, *",
    currentPolicy: ({ cfg, accountId }) =>
      resolvePulseBoardAccount({ cfg: cfg as CoreConfig, accountId }).config.groupPolicy ??
      "allowlist",
    currentEntries: ({ cfg, accountId }) =>
      Object.keys(
        resolvePulseBoardAccount({ cfg: cfg as CoreConfig, accountId }).config.boards ?? {},
      ),
    updatePrompt: ({ cfg, accountId }) =>
      Boolean(resolvePulseBoardAccount({ cfg: cfg as CoreConfig, accountId }).config.boards),
    setPolicy: ({ cfg, accountId, policy }) =>
      setPulseBoardGroupAccess(cfg as CoreConfig, accountId, policy, []),
    resolveAllowlist: async ({ entries }) =>
      [...new Set(entries.map((entry) => normalizeBoardEntry(entry)).filter(Boolean))] as string[],
    applyAllowlist: ({ cfg, accountId, resolved }) =>
      setPulseBoardGroupAccess(cfg as CoreConfig, accountId, "allowlist", resolved as string[]),
  },
  allowFrom: createAllowFromSection({
    helpTitle: "PulseBoard allowlist",
    helpLines: [
      "Allowlist PulseBoard DMs by sender username.",
      'Examples: alice, bob-smith, * (for all users).',
      "Multiple entries: comma-separated.",
    ],
    message: "PulseBoard allowFrom (usernames, comma-separated)",
    placeholder: "alice, bob-smith",
    invalidWithoutCredentialNote: "Use a PulseBoard username or * for open access.",
    parseId: (raw) => {
      const normalized = normalizePulseBoardAllowEntry(raw);
      return normalized || null;
    },
    apply: async ({ cfg, allowFrom }) => setPulseBoardAllowFrom(cfg as CoreConfig, allowFrom),
  }),
  finalize: async ({ cfg, accountId, prompter }) => {
    let next = cfg as CoreConfig;
    const resolved = resolvePulseBoardAccount({ cfg: next, accountId });

    if (resolved.config.groupPolicy === "allowlist") {
      const boardKeys = Object.keys(resolved.config.boards ?? {});
      if (boardKeys.length > 0) {
        const wantsMentions = await prompter.confirm({
          message: "Require @mention to reply in PulseBoard boards?",
          initialValue: true,
        });
        if (!wantsMentions) {
          const boards = resolved.config.boards ?? {};
          const patched = Object.fromEntries(
            Object.entries(boards).map(([key, value]) => [
              key,
              { ...value, requireMention: false },
            ]),
          );
          next = updatePulseBoardAccountConfig(next, accountId, { boards: patched });
        }
      }
    }

    return { cfg: next };
  },
  completionNote: {
    title: "PulseBoard next steps",
    lines: [
      "Next: restart gateway and verify status.",
      "Command: openclaw channels status --probe",
      `Docs: ${formatDocsLink("/channels/pulseboard", "channels/pulseboard")}`,
    ],
  },
  dmPolicy: pulseBoardDmPolicy,
  disable: (cfg) => setSetupChannelEnabled(cfg, channel, false),
};

export { pulseBoardSetupAdapter };

